// 1) OBTENER CAPACIDAD DINÁMICA POR CONCEPTO
let CAPACIDAD_TOTAL = 0;
try {
  // Accedemos al array de datos del nodo "compila_info"
  const info = $('compila_info').first().json.data;

  // Buscamos el objeto cuyo concepto sea "CapacidadReservas"
  const itemCapacidad = info.find(item => item.concept === 'CapacidadReservas');

  // Si lo encuentra, extrae el valor; si no, usa el respaldo de 45
  CAPACIDAD_TOTAL = itemCapacidad ? Number(itemCapacidad.value) : 45;
} catch (error) {
  // Valor de respaldo en caso de error en la búsqueda o el nodo
  CAPACIDAD_TOTAL = 45; 
}

// 2) OBTENER LA SOLICITUD DEL CLIENTE
let solicitud;
try {
  solicitud = $('Data Filter').first().json;
} catch (error) {
  solicitud = { num_personas: 0 };
}

const reqTotal = Number(solicitud.num_personas) || 0;

// 3) PROCESAR DATOS DE LA DB (Ocupación)
const filasDB = $input.all().map(item => item.json);
let textoProximo = "";

const listaMensajes = filasDB.map((fila, index) => {
  const fecha = fila.fecha; 
  const ocupadas = Number(fila.num_personas) || 0;
  const libres = Math.max(0, CAPACIDAD_TOTAL - ocupadas);

  let textoStatus = "";

  // 4) LÓGICA DE DISPONIBILIDAD
  if (reqTotal > 0) {
    if (reqTotal <= libres) {
      textoStatus = "Disponible";
    } else if (libres === 0) {
      textoStatus = "Agotado";
    } else {
      textoStatus = "Capacidad insuficiente";
    }
  } else {
    textoStatus = libres > 0 ? "Disponible" : "Agotado";
  }

  const mensaje = `${fecha} : ${textoStatus} (Ocupación: ${ocupadas}/${CAPACIDAD_TOTAL} personas)`;

  if (index === 0) {
    textoProximo = `${fecha} : ${textoStatus}`;
  }

  return mensaje;
});

// 5) RETORNO DE DATOS
return [
