={{
  (() => {
    const get = (...xs) => xs.find(v => typeof v === 'string' && v.length) || '';

    // Acceder correctamente a los campos dentro de body.data.key
    const remoteJid = get($json.body?.data?.key?.remoteJid);
    const remoteJidAlt = get($json.body?.data?.key?.remoteJidAlt);
    const senderPn = get($json.body?.data?.key?.senderPn, $json.body?.data?.senderPn, $json.key?.senderPn, $json.senderPn);

    // Función para elegir la mejor fuente
    const chooseBestSource = (jid, jidAlt, sender) => {
      const jidHasWhatsapp = jid && jid.toLowerCase().includes('whatsapp');
      const jidAltHasWhatsapp = jidAlt && jidAlt.toLowerCase().includes('whatsapp');

      if (jidHasWhatsapp) {
        return jid;
      } else if (jidAltHasWhatsapp) {
        return jidAlt;
      } else {
        // Si ninguno tiene whatsapp, usar lógica original
        return /@lid$/i.test(jid || '') ? sender : (jid || sender || '');
      }
    };

    const src = chooseBestSource(remoteJid, remoteJidAlt, senderPn);

    // Si no se encontró ninguna fuente válida
    if (!src) return '';

    // Extraer la parte antes del @
    const beforeAt = src.includes('@') ? src.split('@')[0] : src;

    // Remover el + inicial si existe
    const withoutPlus = beforeAt.startsWith('+') ? beforeAt.substring(1) : beforeAt;

    // Extraer solo los dígitos
    const onlyDigits = withoutPlus.replace(/\D/g, '');

    // Tomar los últimos 10 dígitos
    return onlyDigits.slice(-10);
  })()
}}

