return output;

// Define las respuestas posibles para mensajes demasiado largos
const num_mensaje = $json.num_mensaje_largo

const respuestas = [
  "Disculpa, tu mensaje es demasiado extenso para procesarlo. ¿Podrías resumirlo?",
  "Lo siento, no puedo procesar mensajes tan largos. ¿Podrías ser más breve?",
