  "No puedo procesar textos tan largos. Mis habilidades tienen límites de longitud.",
  "Soy solo un asistente con capacidad limitada. ¿Podrías dividir tu mensaje en varios más cortos?",
  "Este formato/longitud no es compatible con mis restricciones actuales.",
  "⚠️ Mensaje demasiado largo. Solo puedo procesar textos de longitud moderada.",
  "Mis capacidades de procesamiento tienen límites. ¿Podrías enviar un mensaje más breve?",
  "El mensaje supera el máximo de caracteres que puedo procesar. ¡Se más conciso!",
  "Necesito que dividas esta información en partes más pequeñas para poder ayudarte.",
  "Tu consulta es demasiado extensa. ¿Podrías focalizarla en un aspecto específico?",
  "Límite de longitud excedido. Por favor, reformula tu mensaje de manera más resumida.",
  "Para poder ayudarte mejor, necesito que tu mensaje sea más breve y directo."
];


// Selecciona una respuesta aleatoria
const respuestaAleatoria = respuestas[Math.floor(Math.random() * respuestas.length)];
const valor =  num_mensaje >= 2 ? 'Disculpa, no puedo procesar estos mensajes, te comunicaré con el personal correspondiente para una mejor atención. Gracias por comunicarte con nosotros. ¡Ten un bonito día!' : respuestaAleatoria;
// Prepara el output para n8n
const output = [{ 
  json: {
    valor: respuestaAleatoria,
    timestamp: new Date().toISOString(),
    tipo: "mensaje_demasiado_largo",
    respuesta: valor

  }

}];


return output;

// Accede al JSON del nodo anterior
const input = items[0].json;

// Genera un número aleatorio
const randomNumber = Math.floor(Math.random() * 1000) + 1;

// Extrae 'output' y el resto de propiedades
const { output, ...restOfInput } = input;

// Mensaje de fallback
const fallbackMessage = "Disculpa, tuve un problema con tu último mensaje, ¿me lo podrías repetir?";

// --- FUNCIÓN DE LIMPIEZA MEJORADA ---
function cleanBotResponse(text) {
    if (typeof text !== 'string') return '';

    let processed = text.trim();

    // 1. ELIMINAR BLOQUES "Used tools" (Incluso si están mal cerrados)
    // Busca desde "[Used tools" hasta el último "]" seguido de un espacio o saludo
    // O simplemente busca el patrón hasta que detecte texto natural.
    const toolBlockRegex = /^\[Used tools:[\s\S]*?\](?=\s*[¡¿A-ZÁÉÍÓÚ])/i;

    if (processed.startsWith('[Used tools:')) {
        // Intentamos primero con Regex para ver si hay un cierre claro antes del mensaje
        if (toolBlockRegex.test(processed)) {
            processed = processed.replace(toolBlockRegex, '').trim();
        } else {
            // Si el Regex falla (bloque mal formado), buscamos el último "Result: [...]" 
            // que es donde suele terminar la cadena de herramientas.
            const lastResultIndex = processed.lastIndexOf('Result:');
            if (lastResultIndex !== -1) {
                // Buscamos el cierre de ese último Result
                const endOfMetadata = processed.indexOf(']', lastResultIndex);
                if (endOfMetadata !== -1) {
                    processed = processed.substring(endOfMetadata + 1).trim();
                } else {
                    // Si ni siquiera hay un corchete de cierre, buscamos el primer signo de admiración o letra mayúscula 
                    // después del último "Result:"
                    const naturalTextMatch = processed.substring(lastResultIndex).match(/[¡¿A-Z].*/);
                    if (naturalTextMatch) {
                        processed = naturalTextMatch[0];
                    }
                }
            }
        }
    }

    // 2. LIMPIEZA DE RESIDUOS (Corchetes, puntos y coma, herramientas sueltas)
    // Esto elimina cosas como "]; Tool: ... Result: []" si quedaron al principio
    processed = processed.replace(/^[\s\];,\n]+/, '');
    processed = processed.replace(/^(Tool|Result|Input):.*?[\]\}]/gi, '');

    // 3. SEGUNDA PASADA DE SEGURIDAD
    // Si todavía empieza con algún residuo técnico, lo limpiamos
    processed = processed.trim().replace(/^[^¡¿A-Z0-9]+/, '');

    return processed;
}

// --- EJECUCIÓN ---

let processedOutput = cleanBotResponse(output);

// 4. LIMPIEZA DE FORMATO MARKDOWN
processedOutput = processedOutput.replace(/\*\*/g, '*');
processedOutput = processedOutput.trim();

// 5. VERIFICACIÓN FINAL
// Si el resultado es muy corto o vacío, usamos fallback
if (processedOutput.length < 2) {
    processedOutput = fallbackMessage;
}

return [
  {
    json: {
      ...restOfInput,      
      output: processedOutput, 
      randomNumber          
    }
  }
];

