// Lee phone_number del nodo "Data Filter" (sin cable)
// Compara últimos 10 dígitos contra el arreglo phone de "Agrupa Blacklist"
// Salida única: { phone_number: "Blacklist" | "<original>" }

function digits(s){ return String(s ?? '').replace(/\D/g,''); }
function last10(s){ const d = digits(s); return d.slice(-10); }

// 1) Construir Set de blacklist desde el input conectado (Agrupa Blacklist)
const blSet = new Set();
for (const it of $input.all()) {
  let arr = it?.json?.phone;
  if (arr == null) continue;
  if (typeof arr === 'string') { try { arr = JSON.parse(arr); } catch {} }
  if (!Array.isArray(arr)) arr = [arr];
  for (const ph of arr) {
    const k = last10(ph);
    if (k) blSet.add(k);
  }
}

// 2) Tomar el número original desde el nodo "Data Filter"
const dfItems = $items('Data Filter');   // <- nombre del nodo EXACTO
if (!dfItems || !dfItems.length) {
  // Si no existe, devolvemos vacío para que el flujo no reviente
  return [{ json: { phone_number: '' } }];
}
let original = String(dfItems[0]?.json?.phone_number ?? '');

// Fallback: si viniera vacío, intenta extraerlo de chat_id dentro del mismo "Data Filter"
if (!original) {
  const cid = dfItems[0]?.json?.chat_id;
  if (cid) {
    const m = String(cid).match(/\d{10,16}/);
    if (m) original = m[0];
  }
}

const out = blSet.has(last10(original)) ? 'Blacklist' : original;
return [{ json: { phone_number: out } }];

// n8n Code node (JS)
// Entrada soportada:
//  a) items[0].json = [ { id, sku_base, categoria, descripcion }, ... ]
//  b) items[0].json.data = [ ... ]
//  c) items = [ { json: { id, sku_base, categoria, descripcion } }, ... ]
//
// Salida:
//  [{ json: { concept: "promocionesejemplo", value: "canal:promocion1, canal:promocion2, ..." } }]

function getArrayFromItems(items) {
  if (Array.isArray(items?.[0]?.json)) return items[0].json;
  if (Array.isArray(items?.[0]?.json?.data)) return items[0].json.data;
  return items.map(it => it.json);
}

function sampleN(arr, n) {
  const a = arr.slice();
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a.slice(0, Math.min(n, a.length));
}

const data = getArrayFromItems(items);

// Concatena "canal" con "promocion", elimina vacíos y dedup (case-insensitive)
const combinedItems = data
  .map(o => {
    const canal = (o?.canal ?? '').toString().trim();
    const promocion = (o?.promocion ?? '').toString().trim();

    // Solo incluir si ambos campos tienen valor
    if (canal && promocion) {
      return `${canal}:${promocion}`;
    }
    return null;
  })
  .filter(Boolean);

const uniqueItems = [...new Map(combinedItems.map(item => [item.toLowerCase(), item])).values()];

const selected = sampleN(uniqueItems, 3);
const value = selected.join(', ');

return [{ json: { concept: 'promocionesejemplo', value } }];

// n8n Code node (JS)
