  "¡Buenas! {marcacorta}{sucursal}. Si quieres una recomendación personalizada, dime cuántos son y qué les gusta comer.",
  "¡Hola! ✨ Puedo ayudarte a conocer el menú de {marcacorta}{sucursal} o gestionar una reservación fácilmente.",
  "¡Bienvenido/a! 👋 Estás en {marcacorta}{sucursal}. Menú, promos, reservaciones o recomendaciones: ¿por dónde empezamos?"
];

// --- 4. UTILIDADES ---
// Selección aleatoria sin repetición
function sampleN(arr, n) {
  const a = arr.slice();
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a.slice(0, Math.min(n, a.length));
}

// Reemplazo de placeholders {marcacorta}, {sucursal}, etc.
function fillPlaceholders(str, vars) {
  return str.replace(/\{(\w+)\}/g, (_, k) => {
    const v = vars[k];

    // Si sucursal viene vacía, no insertamos nada (y evitamos "doble espacio")
    if (k === 'sucursal') {
      if (!v || String(v).trim() === '') return '';
      // Si hay sucursal, la pegamos con un separador natural (ej: " Osaki - Calle 47")
      const s = String(v).trim();
      // si ya viene con guión/paréntesis, no metemos otro
      if (/^[-–—(]/.test(s)) return ` ${s}`;
      return ` - ${s}`;
    }

    return v === undefined || v === null ? `{${k}}` : String(v);
  });
}

// --- 5. PROCESAMIENTO FINAL ---
// Entregamos 3 variantes para rotación (evitar patrón)
const seleccionadas = sampleN(respuestas, 3).map(s =>
  fillPlaceholders(s, {
    marcacorta,
    gastronomia,
    categorias_menu,
    sucursal: sucursalNombre
  })
);

// Limpieza final: colapsa espacios, recorta extremos, y une en multimensaje
const outputValue = seleccionadas.map(s => s.replace(/\s+/g, ' ').trim()).join('\n');

return [
  {
    json: {
      concept: 'ejemplosbienvenida_salon',
      value: outputValue
    }
  }
];

// n8n Code node (JavaScript)
// Convierte el arreglo Aggregate.data[*].message{type, content} en un objeto plano:
// { "Humano_1": "...", "IA_1": "...", "Humano_2": "...", "IA_2": "..." }

const items = $input.all();

// Limpia el texto: recorta, colapsa espacios y, si viene el bloque largo,
// extrae lo que sigue a "Mensaje de Texto o Descripción:"
function cleanText(s) {
  if (!s) return '';
  let t = String(s);

  const marker = 'Mensaje de Texto o Descripción';
  const idx = t.toLowerCase().indexOf(marker.toLowerCase());
  if (idx !== -1) {
    t = t.slice(idx + marker.length);
  }

  // Quita separadores iniciales y colapsa espacios/nuevas líneas
  t = t.replace(/^[\s:.-]+/, '').replace(/\s+/g, ' ').trim();
  return t;
}

// Extrae mensajes desde varias formas posibles
const records = [];
for (const it of items) {
  const j = it.json || {};

  // Si viene como { data: [...] } úsalo; si no, intenta interpretar el propio objeto
  const arr = Array.isArray(j.data) ? j.data : (Array.isArray(j) ? j : (j.data ? [j.data] : [j]));

  for (const row of arr) {
    const msg = row?.message || row;
    const type = (msg?.type || msg?.role || '').toLowerCase();
    const content = msg?.content ?? msg?.text ?? '';

    if (!type || !content) continue;

    const role = (type === 'human' || type === 'user') ? 'Humano' : 'IA';
    records.push({ role, text: cleanText(content) });
  }
}

// Construye objeto plano con claves enumeradas
const out = {};
let h = 1, a = 1;
for (const r of records) {
  if (r.role === 'Humano') out[`Humano_${h++}`] = r.text;
  else out[`IA_${a++}`] = r.text;
}

return [{ json: out }];

// Code (JavaScript) ANTES del Summarization Chain
// Convierte Humano_*/IA_* en un solo bloque de texto ordenado
const it = $input.first().json;
const lines = Object.entries(it)
  .filter(([k]) => /^(Humano|IA)_(\d+)$/i.test(k))
  .sort((a,b) => parseInt(a[0].match(/\d+/)[0],10) - parseInt(b[0].match(/\d+/)[0],10))
  .map(([k,v]) => `${k.startsWith('Humano') ? 'Humano' : 'IA'}: ${String(v).trim()}`);

return [{ json: { text: lines.join('\n') } }];

// n8n Code node (JavaScript)
// Objetivo: formatear/parsear la MISMA entrada; solo normaliza "text" si viene como string.

const resultados = [];

// ---- helpers simples ----
function stripFences(s) {
  return String(s)
    .replace(/^\s*```(?:json)?\s*/i, "")
    .replace(/\s*```$/i, "")
    .trim();
}
function tryParse(s) { try { return JSON.parse(s); } catch { return null; } }
function softUnescape(s) {
  return String(s)
    .replace(/\\n/g, "\n")
    .replace(/\\t/g, "\t")
    .replace(/\\"/g, '"')
    .replace(/\\'/g, "'")
    .replace(/\\\\/g, "\\");
}
/** Parseo multinivel NO intrusivo para strings JSON (hasta 3 niveles). */
function decode(value, maxDepth = 3) {
  let cur = value;
  for (let i = 0; i < maxDepth && typeof cur === "string"; i++) {
    const stripped = stripFences(cur);
    let parsed = tryParse(stripped) ?? tryParse(softUnescape(stripped));
    if (parsed == null) break;
    cur = parsed; // podría seguir siendo string -> continuar bucle
  }
  return cur;
}

// ---- proceso principal ----
for (const item of items) {
  // Extraer el campo "text" del contenido del output
  let rawText = null;

  // Navegar hasta el campo text en la estructura del input
  if (item?.json?.output?.[0]?.content?.[0]?.text) {
    rawText = item.json.output[0].content[0].text;
  } else if (item?.json?.text) {
    rawText = item.json.text;
  } else {
    // Si no se encuentra el campo text, devolver el item original
    resultados.push({ json: item.json });
    continue;
  }

  // Si es string, intenta decodificar TODO el objeto; si ya es objeto, úsalo
  const base = typeof rawText === "string" ? decode(rawText) : rawText;

  // Si no se pudo decodificar el blob completo, devuelve el raw tal cual
  if (typeof base === "string") {
    resultados.push({ json: { text: base } });
    continue;
  }

  // Clona superficialmente para no mutar el original
  const out = { ...base };

  // Solo normaliza campos específicos si vienen como string
  // En este caso, procesamos cualquier campo que sea string JSON
  for (const key in out) {
    if (typeof out[key] === "string") {
      const parsedValue = decode(out[key]);
      if (parsedValue && typeof parsedValue === "object") {
        out[key] = parsedValue;
      }
    }
  }

  resultados.push({ json: out });
}

return resultados;

// n8n Code Node (JavaScript)
// Fuentes:
// - Nodo "Code": info del negocio (marca, agente, contactos, slogan, etc.)
// - Nodo "Normaliza1": campo "VIP" con formato tipo "Sí:9"

function safeJsonParse(maybeJson, fallback) {
  try {
    if (typeof maybeJson !== "string") return maybeJson ?? fallback;
    const s = maybeJson.trim();
    if (!s) return fallback;
    return JSON.parse(s);
  } catch (e) {
    return fallback;
  }
}

function toTitleCase(s) {
  if (!s || typeof s !== "string") return s;
  return s
    .toLowerCase()
    .split(" ")
    .filter(Boolean)
    .map(w => w.charAt(0).toUpperCase() + w.slice(1))
    .join(" ");
}

function pickFirst(arr, predicate) {
  if (!Array.isArray(arr)) return null;
  if (!predicate) return arr[0] ?? null;
  return arr.find(predicate) ?? arr[0] ?? null;
}

function extractNumPersonasFromVIP(vipRaw) {
  // vipRaw esperado: "Sí:9" | "Sí: 9" | "No" | "Si:12" | "Sí:VIP"
  if (vipRaw == null) return null;
  const s = String(vipRaw).trim();

  // Busca el primer entero en el string
  const m = s.match(/(\d{1,3})/);
  if (m) return parseInt(m[1], 10);

  return null;
}

// --------------------
// 1) Obtener inputs
// --------------------
const negocio = $("Code").first()?.json ?? {};
const normaliza = $("Normaliza1").first()?.json ?? {};

// --------------------
// 2) Variables negocio
// --------------------
