      timestamp: new Date().toISOString(),
    },
  },
];

// Código mejorado que divide la respuesta en fragmentos y los ordena correctamente
const resultado = [];
let fragmentIndex = 0;

for (const item of items) {
  if (item.json && typeof item.json.output === 'string') {
    // Dividir por doble salto de línea y filtrar párrafos vacíos
    const parrafos = item.json.output
      .split(/\n\n/)
      .map(x => x.trim())
      .filter(x => x.length > 0);

    // Crear un objeto para cada párrafo con información de orden
    for (let i = 0; i < parrafos.length; i++) {
      const texto = parrafos[i];
      fragmentIndex++;

      resultado.push({ 
        json: { 
          output: texto,
          fragment_index: fragmentIndex,
          total_fragments: parrafos.length,
          chat_id: item.json.chat_id || $('Data Filter').first().json.chat_id,
          instance_name: item.json.instance_name || $('Data Filter').first().json.instance_name,
          apiKey: item.json.apiKey || $('Data Filter').first().json.apiKey,
          url_server: item.json.url_server || $('Data Filter').first().json.url_server
        } 
      });
    }
  }
}

return resultado;

